181→static inline ulp_t
182→ulp32(binary32 a, binary32 b)
183→{
184→    if (a == b)
185→        return 0;
186→    if (isnan(a) && isnan(b))
187→        return 0;
188→    if (isnan(a) || isnan(b)) {
189→#ifdef __RX__
190→        printf("RX fails to generate NaN, ignoring\n");
191→        return 0;
192→#endif
193→        return INV_ULP;
194→    }
195→
196→    ulp_t ulp = 0;
197→    while (a != b) {
198→        a = nextafter32(a, b);
199→        ulp++;
200→        if (ulp == MAX_ULP)
201→            break;
202→    }
203→    return ulp;
204→}
205→
206→static inline ulp_t
207→culp32(cbinary32 a, cbinary32 b)
208→{
209→    if (a == b)
210→        return 0;
211→    binary32 a_r = cabs32(a);
212→    binary32 d_r = cabs32(a - b);
213→    return ulp32(a_r + d_r, a_r);
214→}
